public Action suspend(AtmosphereResource r) {
    switch(r.transport()) {
        case JSONP:
        case LONG_POLLING:
            // 5 seconds timeout for polling transports
            r.suspend(5000L);
            break;
        case SSE:
        case WEBSOCKET:
            // No timeout for streaming transports
            r.suspend(-1);
            break;
        default:
            // 30 seconds default timeout
            r.suspend(30000L);
            break;
    }
    return Action.CONTINUE;
}

